import 'package:dio/dio.dart';

class ApiService {
  static final ApiService _instance = ApiService._internal();
  factory ApiService() => _instance;
  late final Dio _dio;

  ApiService._internal() {
    _dio = Dio(BaseOptions(
      baseUrl: 'https://api.example.com/v1',
      connectTimeout: const Duration(seconds: 10),
      receiveTimeout: const Duration(seconds: 10),
      headers: {'Content-Type': 'application/json'},
    ));
    _dio.interceptors.add(LogInterceptor(requestBody: true, responseBody: true));
    _dio.interceptors.add(InterceptorsWrapper(
      onRequest: (o, h) { h.next(o); },
      onError: (e, h) { h.next(e); },
    ));
  }

  Future<dynamic> get(String path, {Map<String, dynamic>? params}) async {
    try { return (await _dio.get(path, queryParameters: params)).data; }
    on DioException catch (e) { throw _err(e); }
  }

  Future<dynamic> post(String path, {dynamic data}) async {
    try { return (await _dio.post(path, data: data)).data; }
    on DioException catch (e) { throw _err(e); }
  }

  Future<dynamic> put(String path, {dynamic data}) async {
    try { return (await _dio.put(path, data: data)).data; }
    on DioException catch (e) { throw _err(e); }
  }

  Future<dynamic> delete(String path) async {
    try { return (await _dio.delete(path)).data; }
    on DioException catch (e) { throw _err(e); }
  }

  Exception _err(DioException e) {
    switch (e.type) {
      case DioExceptionType.connectionTimeout: return Exception('Ulanish vaqti tugadi');
      case DioExceptionType.receiveTimeout: return Exception('Javob vaqti tugadi');
      default: return Exception('Xatolik');
    }
  }
}

