import 'package:firebase_auth/firebase_auth.dart';

class AuthService {
  final _auth = FirebaseAuth.instance;
  User? get user => _auth.currentUser;
  Stream<User?> get authState => _auth.authStateChanges();

  Future<UserCredential?> signIn(String email, String password) async {
    return await _auth.signInWithEmailAndPassword(email: email, password: password);
  }

  Future<UserCredential?> signUp(String email, String password) async {
    return await _auth.createUserWithEmailAndPassword(email: email, password: password);
  }

  Future<void> signOut() async => await _auth.signOut();

  Future<void> resetPassword(String email) async => await _auth.sendPasswordResetEmail(email: email);
}

import 'dart:convert';
import 'package:http/http.dart' as http;

class RestClient {
  final String baseUrl;
  RestClient(this.baseUrl);

  Future<dynamic> get(String path, {Map<String, String>? headers}) async {
    final resp = await http.get(Uri.parse(baseUrl + path), headers: headers);
    return _handle(resp);
  }

  Future<dynamic> post(String path, {dynamic body, Map<String, String>? headers}) async {
    final resp = await http.post(Uri.parse(baseUrl + path), body: jsonEncode(body),
      headers: {'Content-Type': 'application/json', ...?headers});
    return _handle(resp);
  }

  Future<dynamic> delete(String path, {Map<String, String>? headers}) async {
    final resp = await http.delete(Uri.parse(baseUrl + path), headers: headers);
    return _handle(resp);
  }

  dynamic _handle(http.Response resp) {
    if (resp.statusCode >= 200 && resp.statusCode < 300) return jsonDecode(resp.body);
    throw Exception('Xatolik: ' + resp.statusCode.toString());
  }
}

