import 'package:cloud_firestore/cloud_firestore.dart';

class FirestoreService {
  final _db = FirebaseFirestore.instance;

  Future<void> add(String col, Map<String, dynamic> data) async {
    await _db.collection(col).add(data);
  }

  Future<void> set(String col, String id, Map<String, dynamic> data) async {
    await _db.collection(col).doc(id).set(data);
  }

  Future<DocumentSnapshot> get(String col, String id) async {
    return await _db.collection(col).doc(id).get();
  }

  Stream<QuerySnapshot> stream(String col) {
    return _db.collection(col).snapshots();
  }

  Future<void> update(String col, String id, Map<String, dynamic> data) async {
    await _db.collection(col).doc(id).update(data);
  }

  Future<void> delete(String col, String id) async {
    await _db.collection(col).doc(id).delete();
  }
}

import 'package:graphql_flutter/graphql_flutter.dart';

class GraphQLService {
  static final GraphQLService _i = GraphQLService._();
  factory GraphQLService() => _i;
  late final GraphQLClient _client;

  GraphQLService._() {
    final httpLink = HttpLink('https://api.example.com/graphql');
    _client = GraphQLClient(link: httpLink, cache: GraphQLCache(store: InMemoryStore()));
  }

  Future<QueryResult> query(String q, {Map<String, dynamic>? vars}) async {
    return await _client.query(QueryOptions(document: gql(q), variables: vars));
  }

  Future<QueryResult> mutate(String m, {Map<String, dynamic>? vars}) async {
    return await _client.mutate(MutationOptions(document: gql(m), variables: vars));
  }
}

import 'dart:async';
import 'dart:convert';
import 'package:web_socket_channel/web_socket_channel.dart';

class WebSocketService {
  WebSocketChannel? _channel;
  final _ctrl = StreamController<dynamic>.broadcast();
  Stream<dynamic> get stream => _ctrl.stream;

  void connect(String url) {
    _channel = WebSocketChannel.connect(Uri.parse(url));
    _channel!.stream.listen(
      (data) => _ctrl.add(jsonDecode(data)),
      onError: (e) => _ctrl.addError(e),
      onDone: () => _ctrl.close(),
    );
  }

  void send(dynamic data) => _channel?.sink.add(jsonEncode(data));
  void disconnect() { _channel?.sink.close(); _ctrl.close(); }
}

