class CustomPaintPage extends StatelessWidget {
  const CustomPaintPage({super.key});
  @override
  Widget build(BuildContext context) {
    return Scaffold(appBar: AppBar(title: const Text('Custom Paint')),
      body: Center(child: CustomPaint(size: const Size(300, 300), painter: MyPainter())));
  }
}

class MyPainter extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()..color = Colors.blue..strokeWidth = 4..style = PaintingStyle.stroke;
    canvas.drawCircle(Offset(size.width / 2, size.height / 2), 100, paint);
    paint.color = Colors.red;
    canvas.drawRect(Rect.fromLTWH(50, 50, 200, 200), paint);
    paint.color = Colors.green;
    final path = Path()..moveTo(150, 50)..lineTo(250, 250)..lineTo(50, 250)..close();
    canvas.drawPath(path, paint);
  }
  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => false;
}

