import 'package:dartz/dartz.dart';
import 'package:dio/dio.dart';
import '../../domain/repositories/auth_repository.dart';
import '../../domain/entities/user_entity.dart';
import '../../../../core/error/failures.dart';
import '../../../../core/network/dio_client.dart';

class AuthRepositoryImpl implements AuthRepository {
  final DioClient dioClient;

  AuthRepositoryImpl({required this.dioClient});

  @override
  Future<Either<Failure, UserEntity>> login(String email, String password) async {
    try {
      final response = await dioClient.client.post(
        '/auth/login',
        data: {'email': email, 'password': password},
      );
      return Right(UserEntity.fromJson(response.data['user']));
    } on DioException catch (e) {
      return Left(ServerFailure(message: e.message ?? 'Server error'));
    }
  }

  @override
  Future<Either<Failure, UserEntity>> register(String name, String email, String password) async {
    try {
      final response = await dioClient.client.post(
        '/auth/register',
        data: {'name': name, 'email': email, 'password': password},
      );
      return Right(UserEntity.fromJson(response.data['user']));
    } on DioException catch (e) {
      return Left(ServerFailure(message: e.message ?? 'Server error'));
    }
  }

  @override
  Future<Either<Failure, void>> logout() async {
    try {
      await dioClient.client.post('/auth/logout');
      return const Right(null);
    } on DioException catch (e) {
      return Left(ServerFailure(message: e.message ?? 'Server error'));
    }
  }

  @override
  Future<Either<Failure, UserEntity>> getCurrentUser() async {
    try {
      final response = await dioClient.client.get('/auth/me');
      return Right(UserEntity.fromJson(response.data['user']));
    } on DioException catch (e) {
      return Left(ServerFailure(message: e.message ?? 'Server error'));
    }
  }
}

