import 'package:flutter_bloc/flutter_bloc.dart';
import 'counter_event.dart';
import 'counter_state.dart';

class CounterBloc extends Bloc<CounterEvent, CounterState> {
  CounterBloc() : super(const CounterState()) {
    on<CounterInitialized>(_onInitialized);
    on<CounterIncremented>(_onIncremented);
    on<CounterDecremented>(_onDecremented);
    on<CounterMultiplied>(_onMultiplied);
    on<CounterReset>(_onReset);
    on<CounterAsyncOperation>(_onAsyncOperation);
  }

  Future<void> _onInitialized(CounterInitialized event, Emitter<CounterState> emit) async {
    emit(state.copyWith(status: CounterStatus.loading));
    await Future.delayed(const Duration(milliseconds: 500));
    emit(state.copyWith(status: CounterStatus.success, value: 0));
  }

  void _onIncremented(CounterIncremented event, Emitter<CounterState> emit) {
    emit(state.copyWith(value: state.value + 1, status: CounterStatus.success));
  }

  void _onDecremented(CounterDecremented event, Emitter<CounterState> emit) {
    emit(state.copyWith(value: state.value - 1, status: CounterStatus.success));
  }

  void _onMultiplied(CounterMultiplied event, Emitter<CounterState> emit) {
    emit(state.copyWith(value: state.value * event.factor, status: CounterStatus.success));
  }

  void _onReset(CounterReset event, Emitter<CounterState> emit) {
    emit(const CounterState(status: CounterStatus.success));
  }

  Future<void> _onAsyncOperation(CounterAsyncOperation event, Emitter<CounterState> emit) async {
    emit(state.copyWith(status: CounterStatus.loading));
    try {
      await Future.delayed(const Duration(seconds: 2));
      final result = state.value * state.value;
      emit(state.copyWith(value: result, status: CounterStatus.success));
    } catch (e) {
      emit(state.copyWith(status: CounterStatus.failure, errorMessage: e.toString()));
    }
  }
}

sealed class CounterEvent {
  const CounterEvent();
}

class CounterInitialized extends CounterEvent {
  const CounterInitialized();
}

class CounterIncremented extends CounterEvent {
  const CounterIncremented();
}

class CounterDecremented extends CounterEvent {
  const CounterDecremented();
}

class CounterMultiplied extends CounterEvent {
  final int factor;
  const CounterMultiplied({required this.factor});
}

class CounterReset extends CounterEvent {
  const CounterReset();
}

class CounterAsyncOperation extends CounterEvent {
  const CounterAsyncOperation();
}

enum CounterStatus { initial, loading, success, failure }

class CounterState {
  final int value;
  final CounterStatus status;
  final String? errorMessage;

  const CounterState({
    this.value = 0,
    this.status = CounterStatus.initial,
    this.errorMessage,
  });

  CounterState copyWith({
    int? value,
    CounterStatus? status,
    String? errorMessage,
  }) {
    return CounterState(
      value: value ?? this.value,
      status: status ?? this.status,
      errorMessage: errorMessage ?? this.errorMessage,
    );
  }

  bool get isLoading => status == CounterStatus.loading;
  bool get isSuccess => status == CounterStatus.success;
  bool get isFailure => status == CounterStatus.failure;
}

