final postsRepositoryProvider = Provider<PostsRepository>((ref) {
  return PostsRepository();
});

final postsProvider = FutureProvider.autoDispose<List<PostModel>>((ref) async {
  final repository = ref.watch(postsRepositoryProvider);
  ref.keepAlive();
  return repository.getPosts();
});

final postDetailProvider = FutureProvider.family.autoDispose<PostModel, int>((ref, id) async {
  final repository = ref.watch(postsRepositoryProvider);
  return repository.getPostById(id);
});

final searchQueryProvider = StateProvider<String>((ref) => '');

final filteredPostsProvider = Provider<AsyncValue<List<PostModel>>>((ref) {
  final postsAsync = ref.watch(postsProvider);
  final query = ref.watch(searchQueryProvider);

  return postsAsync.whenData((posts) {
    if (query.isEmpty) return posts;
    return posts.where((p) =>
      p.title.toLowerCase().contains(query.toLowerCase()) ||
      p.body.toLowerCase().contains(query.toLowerCase())
    ).toList();
  });
});

final postsNotifierProvider = StateNotifierProvider<PostsNotifier, AsyncValue<List<PostModel>>>((ref) {
  return PostsNotifier(ref);
});

class PostsNotifier extends StateNotifier<AsyncValue<List<PostModel>>> {
  final Ref ref;

  PostsNotifier(this.ref) : super(const AsyncValue.loading()) {
    loadPosts();
  }

  Future<void> loadPosts() async {
    state = const AsyncValue.loading();
    try {
      final posts = await ref.read(postsRepositoryProvider).getPosts();
      state = AsyncValue.data(posts);
    } catch (e, st) {
      state = AsyncValue.error(e, st);
    }
  }

  Future<void> addPost(PostModel post) async {
    state = const AsyncValue.loading();
    try {
      final newPost = await ref.read(postsRepositoryProvider).createPost(post);
      state = AsyncValue.data([...state.value ?? [], newPost]);
    } catch (e, st) {
      state = AsyncValue.error(e, st);
    }
  }

  Future<void> deletePost(int id) async {
    try {
      await ref.read(postsRepositoryProvider).deletePost(id);
      state = AsyncValue.data(
        (state.value ?? []).where((p) => p.id != id).toList(),
      );
    } catch (e, st) {
      state = AsyncValue.error(e, st);
    }
  }
}

class PostModel {
  final int id;
  final int userId;
  final String title;
  final String body;
  final DateTime createdAt;

  const PostModel({
    required this.id,
    required this.userId,
    required this.title,
    required this.body,
    required this.createdAt,
  });

  factory PostModel.fromJson(Map<String, dynamic> json) {
    return PostModel(
      id: json['id'] ?? 0,
      userId: json['userId'] ?? 0,
      title: json['title'] ?? '',
      body: json['body'] ?? '',
      createdAt: DateTime.now(),
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'userId': userId,
      'title': title,
      'body': body,
    };
  }

  PostModel copyWith({
    int? id,
    int? userId,
    String? title,
    String? body,
  }) {
    return PostModel(
      id: id ?? this.id,
      userId: userId ?? this.userId,
      title: title ?? this.title,
      body: body ?? this.body,
      createdAt: createdAt,
    );
  }
}

import 'package:dio/dio.dart';
import '../models/post_model.dart';

class PostsRepository {
  final Dio _dio = Dio(BaseOptions(baseUrl: 'https://jsonplaceholder.typicode.com'));

  Future<List<PostModel>> getPosts() async {
    final response = await _dio.get('/posts');
    return (response.data as List).map((json) => PostModel.fromJson(json)).toList();
  }

  Future<PostModel> getPostById(int id) async {
    final response = await _dio.get('/posts/$id');
    return PostModel.fromJson(response.data);
  }

  Future<PostModel> createPost(PostModel post) async {
    final response = await _dio.post('/posts', data: post.toJson());
    return PostModel.fromJson(response.data);
  }

  Future<void> deletePost(int id) async {
    await _dio.delete('/posts/$id');
  }
}

