import 'dart:async';
import 'dart:convert';
import 'package:web_socket_channel/web_socket_channel.dart';

class ChatService {
  WebSocketChannel? _channel;
  final _messageController = StreamController<Map<String, dynamic>>.broadcast();
  final _presenceController = StreamController<List<String>>.broadcast();
  final _typingController = StreamController<String>.broadcast();
  bool _isConnected = false;

  Stream<Map<String, dynamic>> get messages => _messageController.stream;
  Stream<List<String>> get presence => _presenceController.stream;
  Stream<String> get typing => _typingController.stream;
  bool get isConnected => _isConnected;

  void connect(String url, String token) {
    _channel = WebSocketChannel.connect(Uri.parse('$url?token=$token'));
    _isConnected = true;

    _channel!.stream.listen(
      (data) {
        final json = jsonDecode(data);
        switch (json['type']) {
          case 'message':
            _messageController.add(json);
            break;
          case 'presence':
            _presenceController.add(List<String>.from(json['users']));
            break;
          case 'typing':
            _typingController.add(json['userId']);
            break;
        }
      },
      onDone: () {
        _isConnected = false;
        _reconnect(url, token);
      },
      onError: (error) {
        _isConnected = false;
      },
    );
  }

  void _reconnect(String url, String token) {
    Future.delayed(const Duration(seconds: 3), () {
      if (!_isConnected) connect(url, token);
    });
  }

  void sendMessage(String roomId, String content) {
    if (_channel == null) return;
    _channel!.sink.add(jsonEncode({
      'type': 'message',
      'roomId': roomId,
      'content': content,
      'timestamp': DateTime.now().toIso8601String(),
    }));
  }

  void sendTyping(String roomId) {
    if (_channel == null) return;
    _channel!.sink.add(jsonEncode({
      'type': 'typing',
      'roomId': roomId,
    }));
  }

  void joinRoom(String roomId) {
    if (_channel == null) return;
    _channel!.sink.add(jsonEncode({
      'type': 'join',
      'roomId': roomId,
    }));
  }

  void disconnect() {
    _channel?.sink.close();
    _isConnected = false;
  }

  void dispose() {
    disconnect();
    _messageController.close();
    _presenceController.close();
    _typingController.close();
  }
}

import 'package:flutter/material.dart';
import '../services/chat_service.dart';

class ChatPage extends StatefulWidget {
  final String roomId;
  const ChatPage({super.key, required this.roomId});

  @override
  State<ChatPage> createState() => _ChatPageState();
}

class _ChatPageState extends State<ChatPage> {
  final ChatService _chatService = ChatService();
  final TextEditingController _controller = TextEditingController();
  final ScrollController _scrollController = ScrollController();
  final List<Map<String, dynamic>> _messages = [];
  List<String> _onlineUsers = [];
  String? _typingUser;

  @override
  void initState() {
    super.initState();
    _chatService.connect('wss://api.example.com/ws', 'token');
    _chatService.joinRoom(widget.roomId);
    _chatService.messages.listen((msg) {
      setState(() => _messages.add(msg));
      _scrollToBottom();
    });
    _chatService.presence.listen((users) {
      setState(() => _onlineUsers = users);
    });
    _chatService.typing.listen((userId) {
      setState(() => _typingUser = userId);
      Future.delayed(const Duration(seconds: 3), () {
        if (mounted) setState(() => _typingUser = null);
      });
    });
  }

  void _scrollToBottom() {
    Future.delayed(const Duration(milliseconds: 100), () {
      if (_scrollController.hasClients) {
        _scrollController.animateTo(
          _scrollController.position.maxScrollExtent,
          duration: const Duration(milliseconds: 300),
          curve: Curves.easeOut,
        );
      }
    });
  }

  void _sendMessage() {
    final text = _controller.text.trim();
    if (text.isEmpty) return;
    _chatService.sendMessage(widget.roomId, text);
    _controller.clear();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Room: \${widget.roomId}'),
        actions: [
          Center(
            child: Padding(
              padding: const EdgeInsets.only(right: 16),
              child: Text(
                '\${_onlineUsers.length} online',
                style: const TextStyle(fontSize: 12),
              ),
            ),
          ),
        ],
      ),
      body: Column(
        children: [
          Expanded(
            child: ListView.builder(
              controller: _scrollController,
              padding: const EdgeInsets.all(16),
              itemCount: _messages.length,
              itemBuilder: (context, index) {
                final msg = _messages[index];
                return ChatBubble(
                  message: msg['content'] ?? '',
                  isMe: msg['isMe'] ?? false,
                  timestamp: msg['timestamp'] ?? '',
                );
              },
            ),
          ),
          if (_typingUser != null)
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 16),
              child: Text(
                '\$_typingUser is typing...',
                style: TextStyle(fontSize: 12, color: Colors.grey[600]),
              ),
            ),
          Container(
            padding: const EdgeInsets.all(8),
            decoration: BoxDecoration(
              color: Theme.of(context).colorScheme.surface,
              border: Border(top: BorderSide(color: Colors.grey[300]!)),
            ),
            child: Row(
              children: [
                Expanded(
                  child: TextField(
                    controller: _controller,
                    decoration: const InputDecoration(
                      hintText: 'Type a message...',
                      border: OutlineInputBorder(),
                      contentPadding: EdgeInsets.symmetric(horizontal: 16, vertical: 8),
                    ),
                    onChanged: (_) => _chatService.sendTyping(widget.roomId),
                    onSubmitted: (_) => _sendMessage(),
                  ),
                ),
                const SizedBox(width: 8),
                IconButton.filled(
                  onPressed: _sendMessage,
                  icon: const Icon(Icons.send),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  @override
  void dispose() {
    _chatService.dispose();
    _controller.dispose();
    _scrollController.dispose();
    super.dispose();
  }
}

