    return Center(
      child: AnimatedBuilder(
        animation: _controller,
        builder: (context, child) {
          final now = DateTime.now();
          return CustomPaint(
            size: const Size(150, 150),
            painter: ClockPainter(
              seconds: _controller.value * 60,
              minutes: now.minute.toDouble(),
              hours: now.hour.toDouble(),
            ),
          );
        },
      ),
    );
  }

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }
}

class ClockPainter extends CustomPainter {
  final double seconds;
  final double minutes;
  final double hours;

  ClockPainter({
    required this.seconds,
    required this.minutes,
    required this.hours,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final center = Offset(size.width / 2, size.height / 2);
    final radius = min(size.width, size.height) / 2;

    final bgPaint = Paint()..color = Colors.grey[200]!;
    canvas.drawCircle(center, radius, bgPaint);

    final borderPaint = Paint()
      ..color = Colors.purple
      ..style = PaintingStyle.stroke
      ..strokeWidth = 3;
    canvas.drawCircle(center, radius, borderPaint);

    _drawHand(canvas, center, radius * 0.6, seconds * 6, Colors.red, 2);
    _drawHand(canvas, center, radius * 0.45, minutes * 6, Colors.blue, 3);
    _drawHand(canvas, center, radius * 0.3, hours * 30, Colors.black, 4);

    final centerDot = Paint()..color = Colors.black;
    canvas.drawCircle(center, 5, centerDot);
  }

  void _drawHand(Canvas canvas, Offset center, double length, double angle, Color color, double width) {
    final paint = Paint()
      ..color = color
      ..strokeWidth = width
      ..strokeCap = StrokeCap.round;
    final radians = angle * pi / 180 - pi / 2;
    final end = Offset(
      center.dx + length * cos(radians),
      center.dy + length * sin(radians),
    );
    canvas.drawLine(center, end, paint);
  }

  @override
  bool shouldRepaint(covariant ClockPainter oldDelegate) => true;
}

import 'dart:math';
import 'package:flutter/material.dart';

class MorphingShape extends StatefulWidget {
  const MorphingShape({super.key});

  @override
  State<MorphingShape> createState() => _MorphingShapeState();
}

class _MorphingShapeState extends State<MorphingShape>
    with SingleTickerProviderStateMixin {
  late final AnimationController _controller;
  late final Animation<double> _animation;

  @override
  void initState() {
    super.initState();
    _controller = AnimationController(
      duration: const Duration(milliseconds: 1500),
      vsync: this,
    );
    _animation = Tween<double>(begin: 0, end: 1).animate(
      CurvedAnimation(parent: _controller, curve: Curves.easeInOut),
    );
    _controller.repeat(reverse: true);
  }

  @override
  Widget build(BuildContext context) {
    return Center(
      child: AnimatedBuilder(
        animation: _animation,
        builder: (context, child) {
          return CustomPaint(
            size: const Size(150, 150),
            painter: ShapePainter(progress: _animation.value),
          );
        },
      ),
    );
  }

  @override
  void dispose() {
