    super.dispose();
  }
}

class ShapePainter extends CustomPainter {
  final double progress;

  ShapePainter({required this.progress});

  @override
  void paint(Canvas canvas, Size size) {
    final center = Offset(size.width / 2, size.height / 2);
    final radius = min(size.width, size.height) / 3;

    final paint = Paint()
      ..shader = LinearGradient(
        colors: [Colors.purple, Colors.blue, Colors.cyan],
      ).createShader(Rect.fromCircle(center: center, radius: radius));

    final path = Path();
    final sides = 3 + (progress * 5).floor();
    final angle = 2 * pi / sides;

    for (int i = 0; i < sides; i++) {
      final x = center.dx + radius * cos(angle * i - pi / 2);
      final y = center.dy + radius * sin(angle * i - pi / 2);
      if (i == 0) {
        path.moveTo(x, y);
      } else {
        path.lineTo(x, y);
      }
    }
    path.close();

    canvas.drawPath(path, paint);
  }

  @override
  bool shouldRepaint(covariant ShapePainter oldDelegate) => true;
}

import 'dart:math';
import 'package:flutter/material.dart';

class ParticleEffect extends StatefulWidget {
  const ParticleEffect({super.key});

  @override
  State<ParticleEffect> createState() => _ParticleEffectState();
}

class _ParticleEffectState extends State<ParticleEffect>
    with SingleTickerProviderStateMixin {
  late final AnimationController _controller;
  final List<Particle> _particles = [];
  final Random _random = Random();

  @override
  void initState() {
    super.initState();
    _controller = AnimationController(
      duration: const Duration(milliseconds: 16),
      vsync: this,
    )..addListener(_updateParticles);

    for (int i = 0; i < 50; i++) {
      _particles.add(Particle(
        x: _random.nextDouble() * 300,
        y: _random.nextDouble() * 200,
        vx: (_random.nextDouble() - 0.5) * 2,
        vy: (_random.nextDouble() - 0.5) * 2,
        radius: _random.nextDouble() * 4 + 2,
        color: Colors.primaries[_random.nextInt(Colors.primaries.length)],
      ));
    }
    _controller.repeat();
  }

  void _updateParticles() {
    for (var p in _particles) {
      p.x += p.vx;
      p.y += p.vy;
      if (p.x < 0 || p.x > 300) p.vx *= -1;
      if (p.y < 0 || p.y > 200) p.vy *= -1;
    }
    setState(() {});
  }

  @override
  Widget build(BuildContext context) {
    return CustomPaint(
      size: const Size(300, 200),
      painter: ParticlePainter(particles: _particles),
    );
  }

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }
}

class Particle {
  double x, y, vx, vy, radius;
  Color color;
  Particle({
    required this.x,
    required this.y,
    required this.vx,
    required this.vy,
    required this.radius,
    required this.color,
  });
}

class ParticlePainter extends CustomPainter {
  final List<Particle> particles;

  ParticlePainter({required this.particles});

  @override
  void paint(Canvas canvas, Size size) {
    for (var p in particles) {
      final paint = Paint()..color = p.color.withOpacity(0.7);
      canvas.drawCircle(Offset(p.x, p.y), p.radius, paint);
    }
  }

  @override
  bool shouldRepaint(covariant ParticlePainter oldDelegate) => true;
}

