import 'package:flutter/services.dart';

class PlatformService {
  static const _channel = MethodChannel('com.example/app');
  static const _eventChannel = EventChannel('com.example/events');

  static Future<int> getBatteryLevel() async {
    try {
      final result = await _channel.invokeMethod<int>('getBatteryLevel');
      return result ?? -1;
    } on PlatformException catch (e) {
      print('Error: \${e.message}');
      return -1;
    }
  }

  static Future<String> getDeviceInfo() async {
    try {
      final result = await _channel.invokeMethod<String>('getDeviceInfo');
      return result ?? 'Unknown';
    } on PlatformException catch (e) {
      print('Error: \${e.message}');
      return 'Error';
    }
  }

  static Future<dynamic> callNativeMethod(Map<String, dynamic> args) async {
    try {
      final result = await _channel.invokeMethod('callNativeMethod', args);
      return result;
    } on PlatformException catch (e) {
      print('Error: \${e.message}');
      return null;
    }
  }

  static Stream<dynamic> get nativeEvents {
    return _eventChannel.receiveBroadcastStream();
  }
}

