import 'package:flutter/material.dart';
import 'package:flutter/rendering.dart';

class CircularLayout extends StatelessWidget {
  final List<Widget> children;
  const CircularLayout({super.key, required this.children});

  @override
  Widget build(BuildContext context) {
    return CustomMultiChildLayout(
      delegate: CircularLayoutDelegate(count: children.length),
      children: children.asMap().entries.map((entry) {
        return LayoutId(
          id: entry.key,
          child: entry.value,
        );
      }).toList(),
    );
  }
}

class CircleItem extends StatelessWidget {
  final Color color;
  final String label;
  const CircleItem({super.key, required this.color, required this.label});

  @override
  Widget build(BuildContext context) {
    return Container(
      width: 60,
      height: 60,
      decoration: BoxDecoration(
        color: color,
        shape: BoxShape.circle,
        boxShadow: [
          BoxShadow(color: color.withOpacity(0.3), blurRadius: 8, offset: const Offset(0, 4)),
        ],
      ),
      child: Center(
        child: Text(label, style: const TextStyle(color: Colors.white, fontWeight: FontWeight.bold)),
      ),
    );
  }
}

class CircularLayoutDelegate extends MultiChildLayoutDelegate {
  final int count;

  CircularLayoutDelegate({required this.count});

  @override
  void performLayout(Size size) {
    final center = Offset(size.width / 2, size.height / 2);
    final radius = size.width / 3;

    for (int i = 0; i < count; i++) {
      final angle = (2 * 3.14159 * i / count) - 3.14159 / 2;
      final childSize = const Size(60, 60);
      final offset = Offset(
        center.dx + radius * cos(angle) - childSize.width / 2,
        center.dy + radius * sin(angle) - childSize.height / 2,
      );
      layoutChild(i, BoxConstraints.tight(childSize));
      positionChild(i, offset);
    }
  }

  @override
  bool shouldRelayout(covariant CircularLayoutDelegate oldDelegate) {
    return count != oldDelegate.count;
  }
}

