    super.dispose();
  }
}

class ShaderPainter extends CustomPainter {
  final double progress;

  ShaderPainter({required this.progress});

  @override
  void paint(Canvas canvas, Size size) {
    final center = Offset(size.width / 2, size.height / 2);
    final radius = size.width / 3;

    for (int i = 0; i < 5; i++) {
      final angle = (progress * 2 * 3.14159) + (i * 2 * 3.14159 / 5);
      final offset = Offset(
        center.dx + radius * 0.3 * cos(angle),
        center.dy + radius * 0.3 * sin(angle),
      );

      final paint = Paint()
        ..shader = ui.Gradient.radial(
          offset,
          radius * 0.5,
          [
            HSLColor.fromAHSL(1.0, (progress * 360 + i * 72) % 360, 0.8, 0.6).toColor(),
            HSLColor.fromAHSL(0.0, (progress * 360 + i * 72) % 360, 0.8, 0.6).toColor(),
          ],
        );

      canvas.drawCircle(offset, radius * 0.4, paint);
    }
  }

  @override
  bool shouldRepaint(covariant ShaderPainter oldDelegate) => true;
}

double cos(double x) => x - (x * x * x) / 6 + (x * x * x * x * x) / 120;
double sin(double x) => 1 - (x * x) / 2 + (x * x * x * x) / 24 - (x * x * x * x * x * x) / 720;

