  }

  @override
  bool shouldRebuild(covariant _SliverHeaderDelegate oldDelegate) {
    return child != oldDelegate.child;
  }
}

abstract class State<S, E> {
  final S state;
  final Map<E, Transition<S, E>> transitions;

  State({required this.state, this.transitions = const {}});

  Transition<S, E>? transition(E event) => transitions[event];
}

class Transition<S, E> {
  final S nextState;
  final void Function()? action;

  Transition({required this.nextState, this.action});
}

class StateMachine<S, E> {
  State<S, E> currentState;
  final Map<S, State<S, E>> states;
  final List<Function(S, S)> listeners = [];

  StateMachine({required this.states, required this currentState});

  void addListener(Function(S, S) listener) => listeners.add(listener);

  bool fire(E event) {
    final transition = currentState.transition(event);
    if (transition == null) return false;

    final previousState = currentState.state;
    transition.action?.call();
    currentState = states[transition.nextState]!;

    for (final listener in listeners) {
      listener(previousState, currentState.state);
    }
    return true;
  }

  S get state => currentState.state;
}

import '../../core/state_machine.dart';

enum OrderEvent { submit, confirm, ship, deliver, cancel }
enum OrderStatus { draft, pending, confirmed, shipped, delivered, cancelled }

class OrderStateMachine {
  late final StateMachine<OrderStatus, OrderEvent> _machine;

  OrderStateMachine() {
    _machine = StateMachine(
      states: {
        OrderStatus.draft: State(
          state: OrderStatus.draft,
          transitions: {
            OrderEvent.submit: Transition(nextState: OrderStatus.pending),
          },
        ),
        OrderStatus.pending: State(
          state: OrderStatus.pending,
          transitions: {
            OrderEvent.confirm: Transition(nextState: OrderStatus.confirmed),
            OrderEvent.cancel: Transition(nextState: OrderStatus.cancelled),
          },
        ),
        OrderStatus.confirmed: State(
          state: OrderStatus.confirmed,
          transitions: {
            OrderEvent.ship: Transition(nextState: OrderStatus.shipped),
            OrderEvent.cancel: Transition(nextState: OrderStatus.cancelled),
          },
        ),
        OrderStatus.shipped: State(
          state: OrderStatus.shipped,
          transitions: {
            OrderEvent.deliver: Transition(nextState: OrderStatus.delivered),
          },
        ),
        OrderStatus.delivered: State(state: OrderStatus.delivered),
        OrderStatus.cancelled: State(state: OrderStatus.cancelled),
      },
      currentState: State(state: OrderStatus.draft),
    );
  }

  OrderStatus get currentStatus => _machine.state;

  bool fireEvent(OrderEvent event) => _machine.fire(event);

  void addListener(Function(OrderStatus, OrderStatus) listener) {
    _machine.addListener(listener);
  }
}

