import 'package:flutter/material.dart';

class Responsive {
  static double width(BuildContext context) => MediaQuery.of(context).size.width;
  static double height(BuildContext context) => MediaQuery.of(context).size.height;

  static bool isMobile(BuildContext context) => width(context) < 600;
  static bool isTablet(BuildContext context) => width(context) >= 600 && width(context) < 1024;
  static bool isDesktop(BuildContext context) => width(context) >= 1024;

  static T responsive<T>(BuildContext context, {required T mobile, T? tablet, T? desktop}) {
    if (isDesktop(context)) return desktop ?? tablet ?? mobile;
    if (isTablet(context)) return tablet ?? mobile;
    return mobile;
  }
}

class ResponsiveLayout extends StatelessWidget {
  final Widget mobile;
  final Widget? tablet;
  final Widget? desktop;

  const ResponsiveLayout({
    super.key,
    required this.mobile,
    this.tablet,
    this.desktop,
  });

  @override
  Widget build(BuildContext context) {
    return Responsive.responsive(
      context,
      mobile: mobile,
      tablet: tablet,
      desktop: desktop,
    );
  }
}

class FluidText extends StatelessWidget {
  final String text;
  final TextStyle? style;
  final double minScale;
  final double maxScale;

  const FluidText({
    super.key,
    required this.text,
    this.style,
    this.minScale = 0.8,
    this.maxScale = 1.5,
  });

  @override
  Widget build(BuildContext context) {
    final width = Responsive.width(context);
    final scale = (width / 1200).clamp(minScale, maxScale);

    return Text(
      text,
      style: (style ?? const TextStyle()).copyWith(
        fontSize: (style?.fontSize ?? 16) * scale,
      ),
    );
  }
}

