class DataTablePage extends StatefulWidget {
  const DataTablePage({super.key});

  @override
  State<DataTablePage> createState() => _DataTablePageState();
}

class _DataTablePageState extends State<DataTablePage> {
  int _currentPage = 0;
  int _rowsPerPage = 10;
  String _sortColumn = 'name';
  bool _sortAscending = true;
  String _filterQuery = '';

  final List<Map<String, dynamic>> _data = List.generate(
    100,
    (i) => {
      'id': i + 1,
      'name': 'User \${i + 1}',
      'email': 'user\${i + 1}@example.com',
      'role': ['Admin', 'User', 'Editor'][i % 3],
      'status': ['Active', 'Inactive', 'Pending'][i % 3],
    },
  );

  List<Map<String, dynamic>> get _filteredData {
    var data = _data.where((row) {
      return row['name'].toString().toLowerCase().contains(_filterQuery.toLowerCase()) ||
          row['email'].toString().toLowerCase().contains(_filterQuery.toLowerCase());
    }).toList();

    data.sort((a, b) {
      final aVal = a[_sortColumn] ?? '';
      final bVal = b[_sortColumn] ?? '';
      return _sortAscending
          ? aVal.toString().compareTo(bVal.toString())
          : bVal.toString().compareTo(aVal.toString());
    });

    return data;
  }

  @override
  Widget build(BuildContext context) {
    final pageData = _filteredData
        .skip(_currentPage * _rowsPerPage)
        .take(_rowsPerPage)
        .toList();

    return Scaffold(
      appBar: AppBar(title: const Text('Advanced Data Table')),
      body: Column(
        children: [
          Padding(
            padding: const EdgeInsets.all(16),
            child: TextField(
              decoration: const InputDecoration(
                hintText: 'Filter...',
                prefixIcon: Icon(Icons.search),
                border: OutlineInputBorder(),
              ),
              onChanged: (v) => setState(() {
                _filterQuery = v;
                _currentPage = 0;
              }),
            ),
          ),
          Expanded(
            child: SingleChildScrollView(
              scrollDirection: Axis.horizontal,
              child: DataTable(
                sortColumnIndex: ['id', 'name', 'email', 'role', 'status'].indexOf(_sortColumn),
                sortAscending: _sortAscending,
                columns: [
                  DataColumn(label: const Text('ID'), onSort: (i, _) => _sort('id')),
                  DataColumn(label: const Text('Name'), onSort: (i, _) => _sort('name')),
                  DataColumn(label: const Text('Email'), onSort: (i, _) => _sort('email')),
                  DataColumn(label: const Text('Role'), onSort: (i, _) => _sort('role')),
                  DataColumn(label: const Text('Status'), onSort: (i, _) => _sort('status')),
                ],
                rows: pageData.map((row) {
                  return DataRow(cells: [
                    DataCell(Text('${row['id']}')),
                    DataCell(Text('${row['name']}')),
                    DataCell(Text('${row['email']}')),
                    DataCell(Chip(label: Text('${row['role']}'))),
                    DataCell(_buildStatusChip('${row['status']}')),
                  ]);
                }).toList(),
              ),
            ),
          ),
          Padding(
            padding: const EdgeInsets.all(16),
            child: Row(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                IconButton(
                  onPressed: _currentPage > 0
                      ? () => setState(() => _currentPage--)
                      : null,
                  icon: const Icon(Icons.chevron_left),
                ),
                Text('Page \${_currentPage + 1} of \${(_filteredData.length / _rowsPerPage).ceil()}'),
                IconButton(
                  onPressed: (_currentPage + 1) * _rowsPerPage < _filteredData.length
                      ? () => setState(() => _currentPage++)
                      : null,
                  icon: const Icon(Icons.chevron_right),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  void _sort(String column) {
    setState(() {
      if (_sortColumn == column) {
        _sortAscending = !_sortAscending;
      } else {
        _sortColumn = column;
        _sortAscending = true;
      }
    });
  }

  Widget _buildStatusChip(String status) {
    final color = status == 'Active'
        ? Colors.green
        : status == 'Inactive'
            ? Colors.red
            : Colors.orange;
    return Chip(
      label: Text(status, style: const TextStyle(fontSize: 12)),
      backgroundColor: color.withOpacity(0.1),
      labelStyle: TextStyle(color: color),
    );
  }
}

