import 'dart:async';
import 'dart:convert';
import 'package:web_socket_channel/web_socket_channel.dart';

class WebSocketService {
  WebSocketChannel? _channel;
  final _messageController = StreamController<dynamic>.broadcast();
  final _connectionController = StreamController<ConnectionState>.broadcast();
  final _messageQueue = <String>[];
  Timer? _heartbeatTimer;
  Timer? _reconnectTimer;
  bool _isConnected = false;
  int _reconnectAttempts = 0;
  static const int _maxReconnectAttempts = 5;

  Stream<dynamic> get messages => _messageController.stream;
  Stream<ConnectionState> get connectionState => _connectionController.stream;
  bool get isConnected => _isConnected;

  void connect(String url, {Map<String, String>? headers}) {
    _connectionController.add(ConnectionState.connecting);

    _channel = WebSocketChannel.connect(
      Uri.parse(url),
      headers: headers,
    );

    _channel!.stream.listen(
      (data) {
        _onMessage(data);
      },
      onDone: () {
        _isConnected = false;
        _connectionController.add(ConnectionState.disconnected);
        _attemptReconnect(url, headers: headers);
      },
      onError: (error) {
        _isConnected = false;
        _connectionController.add(ConnectionState.error);
      },
    );

    _isConnected = true;
    _connectionController.add(ConnectionState.connected);
    _startHeartbeat();
    _flushQueue();
  }

  void _onMessage(dynamic data) {
    final json = jsonDecode(data);

    if (json['type'] == 'pong') {
      _reconnectAttempts = 0;
      return;
    }

    _messageController.add(json);
  }

  void send(String type, Map<String, dynamic> payload) {
    final message = jsonEncode({
      'type': type,
      'payload': payload,
      'timestamp': DateTime.now().toIso8601String(),
    });

    if (_isConnected) {
      _channel!.sink.add(message);
    } else {
      _messageQueue.add(message);
    }
  }

  void _startHeartbeat() {
    _heartbeatTimer?.cancel();
    _heartbeatTimer = Timer.periodic(const Duration(seconds: 30), (_) {
      if (_isConnected) {
        send('ping', {});
      }
    });
  }

  void _flushQueue() {
    while (_messageQueue.isNotEmpty && _isConnected) {
      _channel!.sink.add(_messageQueue.removeAt(0));
    }
  }

  void _attemptReconnect(String url, {Map<String, String>? headers}) {
    if (_reconnectAttempts >= _maxReconnectAttempts) return;

    _reconnectTimer?.cancel();
    final delay = Duration(seconds: (2 * (_reconnectAttempts + 1)));
    _reconnectAttempts++;

    _reconnectTimer = Timer(delay, () {
      connect(url, headers: headers);
    });
  }

  void disconnect() {
    _heartbeatTimer?.cancel();
    _reconnectTimer?.cancel();
    _channel?.sink.close();
    _isConnected = false;
    _connectionController.add(ConnectionState.disconnected);
  }

  void dispose() {
    disconnect();
    _messageController.close();
    _connectionController.close();
  }
}

enum ConnectionState { connecting, connected, disconnected, error }

